import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.util.Properties;
import java.util.logging.Level;
import java.util.logging.Logger;

/**
 * Database connection manager for the demo application.
 *
 * Credentials are resolved in the following order:
 * 1. Environment variables (DEMO_DB_HOST, DEMO_DB_PORT, DEMO_DB_NAME, DEMO_DB_USER, DEMO_DB_PASSWORD)
 * 2. A local properties file: db.properties (must be listed in .gitignore)
 *
 * For first-time setup, run: {@code java DatabaseConnection --init}
 * This generates a db.properties file with default demo values that you can adjust.
 */
public class DatabaseConnection {

    private static final Logger LOGGER = Logger.getLogger(DatabaseConnection.class.getName());

    private static final String PROPERTIES_FILE = "db.properties";

    private static final String ENV_PREFIX = "DEMO_DB_";

    private DatabaseConnection() {
        // Utility class
    }

    /**
     * Retrieves a connection to the PostgreSQL database.
     *
     * @return a live database Connection
     * @throws SQLException if a database access error occurs
     * @throws IllegalStateException if configuration is missing
     */
    public static Connection getConnection() throws SQLException {
        Properties config = loadConfiguration();

        String host = getRequiredProperty(config, "host");
        String port = getRequiredProperty(config, "port");
        String database = getRequiredProperty(config, "database");
        String username = getRequiredProperty(config, "username");
        String password = getRequiredProperty(config, "password");

        validatePort(port);

        String jdbcUrl = buildJdbcUrl(host, port, database);

        Properties connectionProps = new Properties();
        connectionProps.setProperty("user", username);
        connectionProps.setProperty("password", password);
        connectionProps.setProperty("ssl", "false"); // Demo only; enable in production
        connectionProps.setProperty("connectTimeout", "5");
        connectionProps.setProperty("socketTimeout", "30");

        try {
            Class.forName("org.postgresql.Driver");
        } catch (ClassNotFoundException e) {
            throw new SQLException("PostgreSQL JDBC driver not found on classpath.", e);
        }

        Connection connection = DriverManager.getConnection(jdbcUrl, connectionProps);
        LOGGER.info("Successfully connected to database: " + database);
        return connection;
    }

    /**
     * Loads configuration from environment variables first, then falls back to properties file.
     */
    private static Properties loadConfiguration() {
        Properties config = new Properties();

        // Try loading from properties file first as base
        Path propsPath = Paths.get(PROPERTIES_FILE);
        if (Files.exists(propsPath)) {
            try (InputStream is = Files.newInputStream(propsPath)) {
                config.load(is);
                LOGGER.info("Loaded configuration from " + PROPERTIES_FILE);
            } catch (IOException e) {
                LOGGER.log(Level.WARNING, "Failed to read " + PROPERTIES_FILE, e);
            }
        }

        // Environment variables override file properties
        overrideFromEnv(config, "host", ENV_PREFIX + "HOST");
        overrideFromEnv(config, "port", ENV_PREFIX + "PORT");
        overrideFromEnv(config, "database", ENV_PREFIX + "NAME");
        overrideFromEnv(config, "username", ENV_PREFIX + "USER");
        overrideFromEnv(config, "password", ENV_PREFIX + "PASSWORD");

        if (config.isEmpty()) {
            throw new IllegalStateException(
                    "No database configuration found. " +
                    "Set environment variables (DEMO_DB_HOST, DEMO_DB_PORT, DEMO_DB_NAME, DEMO_DB_USER, DEMO_DB_PASSWORD) " +
                    "or run 'java DatabaseConnection --init' to generate a " + PROPERTIES_FILE + " file."
            );
        }

        return config;
    }

    private static void overrideFromEnv(Properties config, String propertyKey, String envKey) {
        String envValue = System.getenv(envKey);
        if (envValue != null && !envValue.isBlank()) {
            config.setProperty(propertyKey, envValue);
        }
    }

    private static String getRequiredProperty(Properties config, String key) {
        String value = config.getProperty(key);
        if (value == null || value.isBlank()) {
            throw new IllegalStateException(
                    "Missing required database configuration property: '" + key + "'. " +
                    "Check your " + PROPERTIES_FILE + " or environment variables."
            );
        }
        return value.trim();
    }

    private static void validatePort(String port) {
        try {
            int portNum = Integer.parseInt(port);
            if (portNum < 1 || portNum > 65535) {
                throw new IllegalArgumentException("Port number out of valid range (1-65535): " + port);
            }
        } catch (NumberFormatException e) {
            throw new IllegalArgumentException("Invalid port number: " + port, e);
        }
    }

    private static String buildJdbcUrl(String host, String port, String database) {
        // Validate host and database to prevent JDBC URL injection
        if (!host.matches("[a-zA-Z0-9.\\-]+")) {
            throw new IllegalArgumentException("Invalid hostname: contains disallowed characters.");
        }
        if (!database.matches("[a-zA-Z0-9_]+")) {
            throw new IllegalArgumentException("Invalid database name: contains disallowed characters.");
        }
        return "jdbc:postgresql://" + host + ":" + port + "/" + database;
    }

    /**
     * Generates a default db.properties file for quick demo setup and ensures .gitignore covers it.
     */
    private static void initializePropertiesFile() throws IOException {
        Path propsPath = Paths.get(PROPERTIES_FILE);

        if (Files.exists(propsPath)) {
            System.out.println(PROPERTIES_FILE + " already exists. Not overwriting.");
            return;
        }

        String content = String.join(System.lineSeparator(),
                "# Demo database connection properties",
                "# WARNING: Do not commit this file to version control.",
                "# This file should be listed in .gitignore.",
                "",
                "host=localhost",
                "port=5432",
                "database=demo_db",
                "username=admin",
                "password=Demo123!",
                ""
        );

        Files.writeString(propsPath, content);
        System.out.println("Created " + PROPERTIES_FILE + " with default demo credentials.");
        System.out.println("IMPORTANT: Ensure this file is in your .gitignore before committing.");

        // Automatically add to .gitignore if it exists or create one
        ensureGitignore();
    }

    private static void ensureGitignore() throws IOException {
        Path gitignorePath = Paths.get(".gitignore");
        if (Files.exists(gitignorePath)) {
            String gitignoreContent = Files.readString(gitignorePath);
            if (!gitignoreContent.contains(PROPERTIES_FILE)) {
                Files.writeString(gitignorePath,
                        gitignoreContent + System.lineSeparator() + PROPERTIES_FILE + System.lineSeparator());
                System.out.println("Added " + PROPERTIES_FILE + " to .gitignore.");
            } else {
                System.out.println(PROPERTIES_FILE + " is already in .gitignore.");
            }
        } else {
            Files.writeString(gitignorePath, PROPERTIES_FILE + System.lineSeparator());
            System.out.println("Created .gitignore with " + PROPERTIES_FILE + " entry.");
        }
    }

    /**
     * Closes a connection safely, logging any errors.
     */
    public static void closeQuietly(Connection connection) {
        if (connection != null) {
            try {
                if (!connection.isClosed()) {
                    connection.close();
                    LOGGER.info("Database connection closed.");
                }
            } catch (SQLException e) {
                LOGGER.log(Level.WARNING, "Error closing database connection.", e);
            }
        }
    }

    /**
     * Entry point for initialization and connection testing.
     * Usage:
     *   java DatabaseConnection --init    Generate default db.properties
     *   java DatabaseConnection --test    Test the database connection
     */
    public static void main(String[] args) {
        if (args.length > 0 && "--init".equals(args[0])) {
            try {
                initializePropertiesFile();
            } catch (IOException e) {
                System.err.println("Failed to initialize properties file: " + e.getMessage());
                System.exit(1);
            }
            return;
        }

        if (args.length > 0 && "--test".equals(args[0])) {
            Connection conn = null;
            try {
                conn = getConnection();
                System.out.println("Connection test successful. Database product: "
                        + conn.getMetaData().getDatabaseProductName() + " "
                        + conn.getMetaData().getDatabaseProductVersion());
            } catch (SQLException | IllegalStateException e) {
                System.err.println("Connection test failed: " + e.getMessage());
                System.exit(1);
            } finally {
                closeQuietly(conn);
            }
            return;
        }

        System.out.println("Usage:");
        System.out.println("  java DatabaseConnection --init   Create db.properties with demo defaults");
        System.out.println("  java DatabaseConnection --test   Test the database connection");
    }
}